class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        long long maxVal = 0;
        for (int i = 0; i <= k; i++) {
            long long currMax = 0;
            for (int num : nums) {
                int bits = __builtin_popcount(num);
                if (bits <= k - i) {
                    currMax |= num << (k - i - bits);
                }
            }
            maxVal = max(maxVal, currMax);
        }
        return maxVal;
    }
};
